plugin: FastifyPluginAsyncTypebox = async function (fastify, _opts) {
  fastify.get('/', {
    schema: {
      tags: ['Hello World'],
      description: 'Salute someone via a GET call.',
      summary: 'GET Hello Route',
      querystring: Type.Object({
        name: Type.String({
          default: 'world',
          description: 'Pass the name of the person you want to salute.'
        })
      }),
      response: {
        200: Type.Object({
          hello: Type.String()

        })
      }
    }
  }, (req) => {
    const { name } = req.query
    return { hello: name }
  })

  fastify.post('/', {
    schema: {
      tags: ['Hello World'],
      description: 'Salute someone via a POST call.',
      summary: 'POST Hello Route',
      body: Type.Object({
        name: Type.Optional(Type.String())
      }, {
        description: 'Use the name property to pass the name of the person you want to salute.'
      }),
      response: {
        200: Type.Object({
          hello: Type.String()
        })
      }
    }
  }, async (request) => {
    const { name } = request.body
    const hello = typeof name !== 'undefined' && name !== '' ? name : 'world'

    return { hello }
  })
}

export default function productHandler(server, options, next) {
	server.get(
		'/',
		{ schema: listProductsSchema },
		async (req, res) => {
			req.log.info('list products from db');
			const products = await getAllProducts();
			res.send(products);
		}
	);

	server.get('/:_id', async (req, res) => {
		req.log.info('get one products from db');
		const products = await getOneProduct(req.params._id);
		res.status(200).send(products);
	});

	server.post('/', async (req, res) => {
		req.log.info('Add products to db');
		const products = await createProduct(req.body);
		res.status(201).send(products);
	});

	server.put('/:_id', async (req, res) => {
		req.log.info('Update product to db');
		const products = await updateProduct(req.params._id, req.body);
		res.status(200).send(products);
	});

	server.delete(
		'/:_id',
		{ schema: deleteProductSchema },
		async (req, res) => {
			req.log.info(`delete product ${req.params._id} from db`);
			await deleteProduct(req.params._id);
			res.code(200).send('OK');
		}
	);

	next();
}

plugin: FastifyPluginAsync<Config> = async function fastifyCronPlugin(
  server,
  opts
) {
  const decorator: CronDecorator = {
    jobs: [],
    createJob: function createJob(params) {
      const innerParams: CronJobParameters = {
        ...params,
        onTick: () => params.onTick(server),
        onComplete: () =>
          typeof params.onComplete === 'function'
            ? () => params.onComplete!(server)
            : undefined
      }
      const job: Job = Object.assign(new CronJob(innerParams), {
        name: params.name
      })
      if (params.startWhenReady === true) {
        server.ready(() => job.start())
      }
      decorator.jobs.push(job)
      return job
    },
    getJobByName: function getJobByName(name) {
      return decorator.jobs.find(j => j.name === name)
    },
    startAllJobs: function startAllJobs() {
      decorator.jobs.forEach(job => job.start())
    },
    stopAllJobs: function stopAllJobs() {
      decorator.jobs.forEach(job => job.stop())
    }
  }
  for (const params of opts.jobs || []) {
    if (params) {
      decorator.createJob(params)
    }
  }

  server.decorate('cron', decorator)
  server.addHook('onClose', () => decorator.stopAllJobs())
}

export async function initSwagger(app: FastifyInstance) {
  const swaggerSpec = swaggerJsdoc(options)

  // Write to generated swagger file on development
  if (process.env.NODE_ENV !== 'production') {
    writeFileSync(
      join(__dirname, 'generated', 'swagger.json'),
      JSON.stringify(swaggerSpec, null, 2),
    )
  }

  await app.register(fastifySwagger, {
    mode: 'static',
    specification: {
      path: join(__dirname, 'generated', 'swagger.json'),
      postProcessor(swaggerObject) {
        return swaggerObject
      },
      baseDir: join(__dirname, 'generated'),
    },
  })

  await app.register(fastifySwaggerUi, {
    routePrefix: '/documentation',
    uiConfig: {
      docExpansion: 'full',
      deepLinking: false,
    },
    uiHooks: {
      onRequest(_request, _reply, next) {
        next()
      },
      preHandler(_request, _reply, next) {
        next()
      },
    },
    staticCSP: true,
    transformStaticCSP: (header) => header,
  })
}

configureServer = async (): Promise<FastifyInstance> => {
    const fastify = Fastify({
        logger:
            envToLogger[
                process.env.NODE_ENV as "development" | "production" | "test"
            ] ?? true,
    });

    try {
        await fastify.register(autoload, {
            dir: path.join(__dirname, "plugins"),
            forceESM: true,
        });

        await fastify.register(autoload, {
            dir: path.join(__dirname, "modules"),
            dirNameRoutePrefix: false,
            forceESM: true,

            maxDepth: 1,
            matchFilter: /\/index\.(ts|js)$/,
        });

        fastify.addHook("onClose", async () => {
            // Close all active connections here or directly inside the plugin.
        });

        await fastify.ready();
    } catch (err) {
        fastify.log.fatal(err, "failed to configure server");

        process.exit(1);
    }

    return fastify;
}

