plugin: FastifyPluginCallback<AuthConfig> = (
  fastify,
  options,
  done,
) => {
  const middleware = createAuthMiddleware(options)

  const middie = Middie((err: Error, _req: IncomingMessage, _res: ServerResponse, next: (err?: Error) => void) => {
    next(err)
  })

  middie.use(middleware)

  function runMiddie(req: any, reply: any, next: (err?: Error) => void) {
    req.raw.originalUrl = req.raw.url
    req.raw.id = req.id
    req.raw.hostname = req.hostname
    req.raw.ip = req.ip
    req.raw.ips = req.ips
    req.raw.log = req.log
    req.raw.body = req.body
    req.raw.query = req.query
    reply.raw.log = req.log
    for (const [key, val] of Object.entries(reply.getHeaders())) {
      reply.raw.setHeader(key, val)
    }
    middie.run(req.raw, reply.raw, next)
  }

  fastify.addHook('onRequest', runMiddie)
  // eslint-disable-next-line prefer-arrow-callback
  fastify.decorate('getSession', function (req: FastifyRequest) {
    return getSession(req.raw, options)
  })

  done()
}

function onRequest (req, reply, next) {
  const _pressureHandler = req.routeOptions.config.pressureHandler || pressureHandler
  if (checkMaxEventLoopDelay && eventLoopDelay > maxEventLoopDelay) {
    handlePressure(_pressureHandler, req, reply, next, TYPE_EVENT_LOOP_DELAY, eventLoopDelay)
    return
  }

  if (checkMaxHeapUsedBytes && heapUsed > maxHeapUsedBytes) {
    handlePressure(_pressureHandler, req, reply, next, TYPE_HEAP_USED_BYTES, heapUsed)
    return
  }

  if (checkMaxRssBytes && rssBytes > maxRssBytes) {
    handlePressure(_pressureHandler, req, reply, next, TYPE_RSS_BYTES, rssBytes)
    return
  }

  if (!externalsHealthy) {
    handlePressure(_pressureHandler, req, reply, next, TYPE_HEALTH_CHECK, undefined)
    return
  }

  if (checkMaxEventLoopUtilization && eventLoopUtilized > maxEventLoopUtilization) {
    handlePressure(_pressureHandler, req, reply, next, TYPE_EVENT_LOOP_UTILIZATION, eventLoopUtilized)
    return
  }

  next()
}

