async routeSub(routeName, request, reply) {
    let id = request.params.id || null;
    let doc = null;
    try {
        doc = await this._model.findById(id).exec();
    } catch {
        doc = null;
    }

    if (!doc) {
        reply.callNotFound();
    } else {
        let data = this._apiSubRoutesFunctions[routeName](doc);
        let ret = null;

        if (
            Object.getPrototypeOf(data) &&
            Object.getPrototypeOf(data).constructor.name == 'Query'
        ) {
            ret = await this.getListResponse(data, request, reply);
        } else {
            data = await Promise.resolve(data);
            if (Array.isArray(data)) {
                ret = {};

                ret.items = await this.arrayOfDocsToAPIResponse(
                    data,
                    request
                );
                ret.total = ret.items.length;
            } else {
                ret = await this.docToAPIResponse(data, request);
            }
        }

        reply.send(ret);
    }
}

async function doMigration (): Promise<void> {
  const connection = await mysql.createConnection({
    multipleStatements: true,
    host: process.env.MYSQL_HOST,
    port: Number(process.env.MYSQL_PORT),
    database: process.env.MYSQL_DATABASE,
    user: process.env.MYSQL_USER,
    password: process.env.MYSQL_PASSWORD
  })

  try {
    const migrationDir = path.join(import.meta.dirname, '../migrations')

    if (!fs.existsSync(migrationDir)) {
      throw new Error(
        `Migration directory "${migrationDir}" does not exist. Skipping migrations.`
      )
    }

    const postgrator = new Postgrator({
      migrationPattern: path.join(migrationDir, '*'),
      driver: 'mysql',
      database: process.env.MYSQL_DATABASE,
      execQuery: async (query: string): Promise<PostgratorResult> => {
        const [rows, fields] = await connection.query(query)
        return { rows, fields }
      },
      schemaTable: 'schemaversion'
    })

    await postgrator.migrate()

    console.log('Migration completed!')
  } catch (err) {
    console.error(err)
  } finally {
    await connection.end().catch(err => console.error(err))
  }
}

