#removeOutdatedAppELUs (applicationId) {
  const appELUs = this.#appsMetrics[applicationId]
  if (!appELUs) return

  const now = Date.now()
  const timeWindow = this.#getMetricsTimeWindow()

  for (const workerId in appELUs) {
    const workerELUs = appELUs[workerId]

    let firstValidIndex = -1
    for (let i = 0; i < workerELUs.length; i++) {
      const timestamp = workerELUs[i].timestamp
      if (timestamp >= now - timeWindow) {
        firstValidIndex = i
        break
      }
    }

    if (firstValidIndex > 0) {
      // Remove all outdated entries before the first valid one
      workerELUs.splice(0, firstValidIndex)
    } else if (firstValidIndex === -1) {
      // All entries are outdated, clear the array
      workerELUs.length = 0
    }

    // If there are no more workerELUs, remove the workerId
    if (workerELUs.length === 0) {
      delete appELUs[workerId]
    }
  }
}

function createHttpCacheInterceptor (runtimeConfig) {
  const httpCache = runtimeConfig.httpCache

  const cacheInterceptor = httpCacheInterceptor({
    store: new RemoteCacheStore({
      onRequest: opts => {
        const onHttpCacheRequest = getOnHttpCacheRequest({ throwOnMissing: false })
        if (onHttpCacheRequest) {
          onHttpCacheRequest(opts)
        }
      },
      onCacheHit: opts => {
        const onHttpCacheHit = getOnHttpCacheHit({ throwOnMissing: false })
        if (onHttpCacheHit) {
          onHttpCacheHit(opts)
        }
      },
      onCacheMiss: opts => {
        const onHttpCacheMiss = getOnHttpCacheMiss({ throwOnMissing: false })
        if (onHttpCacheMiss) {
          onHttpCacheMiss(opts)
        }
      },
      logger: getLogger()
    }),
    methods: httpCache.methods ?? ['GET', 'HEAD'],
    origins: parseOrigins(httpCache.origins),
    cacheByDefault: httpCache.cacheByDefault,
    type: httpCache.type,
    logger: getLogger()
  })
  return cacheInterceptor
}

const contentType = this.getHeader('content-type')
  const hasContentType = contentType !== undefined

  if (payload !== null) {
    if (
      // node:stream
      typeof payload.pipe === 'function' ||
      // node:stream/web
      typeof payload.getReader === 'function' ||
      // Response
      (typeof payload === 'object' && toString.call(payload) === '[object Response]')
    ) {
      onSendHook(this, payload)
      return this
    }

    if (payload.buffer instanceof ArrayBuffer) {
      if (!hasContentType) {
        this[kReplyHeaders]['content-type'] = CONTENT_TYPE.OCTET
      }
      const payloadToSend = Buffer.isBuffer(payload)
        ? payload
        : Buffer.from(payload.buffer, payload.byteOffset, payload.byteLength)
      onSendHook(this, payloadToSend)
      return this
    }

    if (!hasContentType && typeof payload === 'string') {
      this[kReplyHeaders]['content-type'] = CONTENT_TYPE.PLAIN
      onSendHook(this, payload)
      return this
    }
  }

async function loadBundle(
  distOutDir: string,
  entryPath: string,
  rootDir: string,
  config: ProdRuntimeConfig,
): Promise<EntryBundle> {
  const parsedNamed = parse(entryPath).name
  const bundleFiles = [`${parsedNamed}.js`, `${parsedNamed}.mjs`]

  const fixWin32Path =
    process.platform === 'win32'
      ? (filePath: string) => new URL(fileUrl(filePath))
      : (filePath: string) => filePath

  let getBundlePath: (serverFile: string) => string | URL
  if (isAbsolute(distOutDir)) {
    getBundlePath = (serverFile: string) => fixWin32Path(resolve(distOutDir, serverFile))
  } else {
    const { packageDirectory } = await import('package-directory')
    const pkgDir = await packageDirectory({ cwd: rootDir })
    if (!pkgDir) {
      throw new Error(`Could not find package root from: ${rootDir}`)
    }
    getBundlePath = (serverFile: string) => fixWin32Path(resolve(pkgDir, distOutDir, serverFile))
  }

  let bundlePath: string | URL | undefined

  for (const serverFile of bundleFiles) {
    bundlePath = getBundlePath(serverFile)
    if (existsSync(bundlePath)) {
      break
    }
  }
  let bundle = await import(bundlePath as string)
  if (typeof bundle.default === 'function') {
    bundle = await bundle.default(config)
  }
  return bundle.default || bundle
}

write(data, _, cb = noop) {
  if (this.destroyed) throw new ERR_STREAM_DESTROYED()

  if (this[kClientError] && data.startsWith('HTTP/')) {
    const [header, body] = data.split('\r\n\r\n')
    const [first, ...headers] = header.split('\r\n')
    const [,code, statusText] = first.split(' ')
    this[kHead] = {
      headers: headers.map((header) => {
        const [name, ...value] = header.split(': ')
        return { name, value: value.join(': ').trim() }
      }).filter(header => header.name.toLowerCase() !== 'content-length'),
      status: `${code} ${statusText}`,
    }
    data = body
    return this.end(data, _, cb)
  }

  const res = this[kRes]

  this[kReadyState].write = true

  res.cork(() => {
    if (this[kHead]) {
      writeHead(res, this[kHead])
      this[kHead] = null
    }

    const drained = res.write(getChunk(data))
    this.bytesWritten += byteLength(data)

    if (drained) return cb()
    drain(this, cb)
  })

  return !this.writableNeedDrain
}

function hasModuleScriptType(openTag: string): boolean {
  let index = '<script'.length

  while (index < openTag.length) {
    while (isWhitespace(openTag[index])) {
      index++
    }

    const char = openTag[index]
    if (char === undefined || char === '>' || (char === '/' && openTag[index + 1] === '>')) {
      return false
    }

    const nameStart = index
    while (
      index < openTag.length &&
      !isWhitespace(openTag[index]) &&
      openTag[index] !== '=' &&
      openTag[index] !== '>'
    ) {
      index++
    }

    const name = openTag.slice(nameStart, index).toLowerCase()

    while (isWhitespace(openTag[index])) {
      index++
    }

    let value = ''
    if (openTag[index] === '=') {
      index++
      while (isWhitespace(openTag[index])) {
        index++
      }
      ;[value, index] = readAttributeValue(openTag, index)
    }

    if (name === 'type' && value.toLowerCase() === 'module') {
      return true
    }
  }

  return false
}
